import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';

const Dashboard = ({ user, onLogout }) => {
  const [stats, setStats] = useState({
    loginTime: new Date().toLocaleString(),
    sessionDuration: '0 minutes',
    lastLogin: 'Today'
  });

  useEffect(() => {
    const startTime = Date.now();
    const interval = setInterval(() => {
      const duration = Math.floor((Date.now() - startTime) / 60000);
      setStats(prev => ({
        ...prev,
        sessionDuration: `${duration} minute${duration !== 1 ? 's' : ''}`
      }));
    }, 60000);

    return () => clearInterval(interval);
  }, []);

  const quickActions = [
    { title: '👤 View Profile', link: '/profile', description: 'Manage your account information' },
    { title: '📖 About App', link: '/about', description: 'Learn about this application' },
    { title: '🔧 Settings', link: '/settings', description: 'Configure your preferences' }
  ];

  return (
    <div className="home-container">
      <div className="home-card">
        <h1>🎉 Welcome Back, {user?.name?.split(' ')[0]}!</h1>
        <p>You have successfully logged in to your dashboard.</p>

        <div className="user-info">
          <h3>👤 Account Information</h3>
          <div className="info-grid">
            <div className="info-item">
              <strong>Name:</strong> {user?.name}
            </div>
            <div className="info-item">
              <strong>Email:</strong> {user?.email}
            </div>
            <div className="info-item">
              <strong>User ID:</strong> {user?.id}
            </div>
          </div>
        </div>

        <div className="session-info">
          <h3>📊 Session Information</h3>
          <div className="info-grid">
            <div className="info-item">
              <strong>Login Time:</strong> {stats.loginTime}
            </div>
            <div className="info-item">
              <strong>Session Duration:</strong> {stats.sessionDuration}
            </div>
            <div className="info-item">
              <strong>Status:</strong> <span className="status-active">🟢 Active</span>
            </div>
          </div>
        </div>

        <div className="quick-actions">
          <h3>⚡ Quick Actions</h3>
          <div className="actions-grid">
            {quickActions.map((action, index) => (
              <Link 
                key={index} 
                to={action.link} 
                className="action-card"
              >
                <h4>{action.title}</h4>
                <p>{action.description}</p>
              </Link>
            ))}
          </div>
        </div>

        <div className="dashboard-actions">
          <button onClick={onLogout} className="logout-btn">
            🚪 Logout
          </button>
        </div>
      </div>
    </div>
  );
};

export default Dashboard;
